function evaluateProperty(listing) {
    // ===== ARV CALCULATION =====
    // DFW market: properties appreciate ~18% after rehab (not 25%)
    // Formula: Purchase Price × 1.18 × 0.97 = ARV
    const baseArv = Math.round(listing.price * 1.18) // Changed from 1.25 to 1.18
    ;
    const adjustedArv = Math.round(baseArv * 0.97);
    // ===== COST BREAKDOWN =====
    // Closing costs: 3% of purchase (not 2%)
    const closingCosts = Math.round(listing.price * 0.03) // Changed from 0.02 to 0.03
    ;
    // Holding costs: 0.5% monthly × 6 months = 3% (not 6%)
    // Realistic: property taxes, insurance, utilities, maintenance for 6 months
    const holdingCosts = Math.round(listing.price * 0.03) // Changed from 0.06 to 0.03
    ;
    // Repair costs: $25/sqft (not $50/sqft implied by 25)
    // $25/sqft is DFW cosmetic rehab standard
    const rehabCosts = Math.round(listing.sqft * 25) // Keep this, it's correct
    ;
    // Total costs: should include selling costs too
    // Selling: 6.5% of ARV (realtor commission 6% + closing ~0.5%)
    const sellingCosts = Math.round(adjustedArv * 0.065);
    // Total investment includes acquisition + repairs + holding + selling
    const totalCosts = listing.price + closingCosts + holdingCosts + rehabCosts + sellingCosts;
    // ===== PROFIT CALCULATION =====
    const netProfit = adjustedArv - totalCosts;
    const profitMargin = netProfit / adjustedArv * 100;
    // ===== PASS CRITERIA =====
    // Must meet 10% profit margin AND have at least $25,000 profit
    const minProfitMargin = 10;
    const minProfitDollars = 25000;
    const checkMargin = profitMargin >= minProfitMargin;
    const checkProfit = netProfit >= minProfitDollars;
    const pass = checkMargin && checkProfit // Changed: must pass BOTH criteria
    ;
    // Build failure reasons
    const failureReasons = [];
    if (!checkMargin) {
        failureReasons.push(`Profit margin ${profitMargin.toFixed(2)}% below 10% threshold`);
    }
    if (!checkProfit) {
        failureReasons.push(`Net profit $${netProfit.toLocaleString()} below $25,000 minimum`);
    }
    return {
        externalId: listing.externalId,
        address: listing.address,
        city: listing.city,
        underwriting: {
            status: pass ? "PASS" : "FAIL",
            arv: {
                baseArv,
                adjustedArv
            },
            costs: {
                purchasePrice: listing.price,
                closingCosts,
                holdingCosts,
                rehabCosts,
                sellingCosts,
                totalCosts
            },
            profit: {
                netProfit,
                profitMargin
            },
            failureReasons: failureReasons
        },
        evaluatedAt: new Date().toISOString()
    };
}
